   232→    static constexpr QuantMode fromDescription(bool quantizeWeights, bool quantizeActivations, bool perToken,
   233→        bool perChannel, bool perGroup, bool useInt4Weights, bool useInt8KvCache, bool useFp8KvCache, bool useFp8Qdq,
