    94→template <typename T>
    95→void runGemm(at::Tensor& out, at::Tensor const& mat1, at::Tensor const& mat2, at::Tensor const& mat1Scale,
    96→    at::Tensor const& mat2Scale, at::Tensor const& globalScale, int64_t m, int64_t n, int64_t k, int64_t batch_count,
    97→    tkc::CutlassGemmConfig const& gemmConfig, FP4GemmType fp4GemmType)
    98→{
    99→    if (fp4GemmType == FP4GemmType::W4A8_MXFP4_MXFP8)
   100→    {
   101→        CutlassFp4GemmRunner<T, FP4GemmType::W4A8_MXFP4_MXFP8> gemmRunner;
   102→        int64_t const wsBytes = gemmRunner.getWorkspaceSize(m, n, k, batch_count);
   103→
   104→        at::Tensor workspace = at::detail::empty_cuda({wsBytes}, at::ScalarType::Char, mat1.device(), std::nullopt);
   105→
   106→        gemmRunner.gemm(out.data_ptr(), mat1.const_data_ptr(), mat2.const_data_ptr(), mat1Scale.const_data_ptr(),
   107→            mat2Scale.const_data_ptr(), globalScale.data_ptr<float>(), m, n, k, batch_count, gemmConfig,
   108→            reinterpret_cast<char*>(workspace.data_ptr()), wsBytes, at::cuda::getCurrentCUDAStream(mat1.get_device()));
   109→    }
   110→    else if (fp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
   111→    {
   112→        CutlassFp4GemmRunner<T, FP4GemmType::W4A4_NVFP4_NVFP4> gemmRunner;
   113→        int64_t const wsBytes = gemmRunner.getWorkspaceSize(m, n, k, batch_count);
   114→
   115→        at::Tensor workspace = at::detail::empty_cuda({wsBytes}, at::ScalarType::Char, mat1.device(), std::nullopt);
   116→
   117→        gemmRunner.gemm(out.data_ptr(), mat1.const_data_ptr(), mat2.const_data_ptr(), mat1Scale.const_data_ptr(),
   118→            mat2Scale.const_data_ptr(), globalScale.data_ptr<float>(), m, n, k, batch_count, gemmConfig,
   119→            reinterpret_cast<char*>(workspace.data_ptr()), wsBytes, at::cuda::getCurrentCUDAStream(mat1.get_device()));
   120→    }
   121→}
   122→
   123→// mat1: [B, M, K / 2], FLOAT4_E2M1X2 or [B, M, K], FLOAT8_E4M3FN
   124→// mat2: [B, N, K / 2], FLOAT4_E2M1X2
   125→// out: [B, M, N], fp16/bf16/fp32
   126→// mat1Scale: ceil(M / 128) * 128 * ceil(K / sfVecSize / 4) * 4, SF_DTYPE (UE4M3 or UE8M0)
   127→// mat2Scale: ceil(N / 128) * 128 * ceil(K / sfVecSize / 4) * 4, SF_DTYPE (UE4M3 or UE8M0)
   128→// globalScale: [1], 1 / (((448 * 6) / mat1.abs().max()) * ((448 * 6) / mat2.abs().max()))
   129→// B = 1 for GEMM op as a special case
   130→// Only W4A4_NVFP4 and W4A8_MXFP4_FP8 are currently supported
   131→at::Tensor fp4_bmm_impl(at::Tensor const& mat1, at::Tensor const& mat2, at::Tensor const& mat1Scale,
   132→    at::Tensor const& mat2Scale, at::Tensor const& globalScale, FP4GemmType fp4GemmType,
   133→    std::optional<c10::ScalarType> out_dtype, bool to_userbuffers = false,
   134→    tkc::CutlassGemmConfig const* maybe_config = nullptr)
   135→{
   136→    if (fp4GemmType == FP4GemmType::W4A8_MXFP4_MXFP8)
   137→    {
   138→        CHECK_INPUT(mat1, torch::kFloat8_e4m3fn);
   139→        CHECK_INPUT(mat2, FLOAT4_E2M1X2);
   140→    }
   141→    else if (fp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
   142→    {
   143→        CHECK_INPUT(mat1, FLOAT4_E2M1X2);
   144→        CHECK_INPUT(mat2, FLOAT4_E2M1X2);
   145→    }
   146→    int mat2_k_scale = fp4GemmType == FP4GemmType::W4A8_MXFP4_MXFP8 ? 2 : 1;
   147→
   148→    CHECK_INPUT(mat1Scale, SF_DTYPE);
   149→    CHECK_INPUT(mat2Scale, SF_DTYPE);
   150→
   151→    CHECK_INPUT(globalScale, at::ScalarType::Float);
   152→
   153→    int64_t m, n, k, b;
   154→    if (mat1.dim() == 2)
   155→    {
   156→        TORCH_CHECK(mat2.dim() == 2, "mat2 must be a matrix");
   157→        TORCH_CHECK(mat1.sizes()[1] == mat2.sizes()[1] * mat2_k_scale, "mat1 and mat2 shapes cannot be multiplied (",
   158→            mat1.sizes()[0], "x", mat1.sizes()[1], " and ", mat2.sizes()[0], "x", mat2.sizes()[1], ")");
   159→        m = mat1.sizes()[0];
   160→        n = mat2.sizes()[0];
   161→        k = mat2.sizes()[1] * 2;
   162→        b = 1;
   163→    }
   164→    else if (mat1.dim() == 3)
   165→    {
   166→        TORCH_CHECK(mat2.dim() == 3, "mat2 must be a batch of matrices");
   167→        TORCH_CHECK(mat1.sizes()[0] == mat2.sizes()[0], "mat1 and mat2 must have the same batch size (",
   168→            mat1.sizes()[0], " and ", mat2.sizes()[0], ")");
   169→        TORCH_CHECK(mat1.sizes()[2] == mat2.sizes()[2] * mat2_k_scale, "mat1 and mat2 shapes cannot be multiplied (",
   170→            mat1.sizes()[1], "x", mat1.sizes()[2], " and ", mat2.sizes()[1], "x", mat2.sizes()[2], ")");
   171→        m = mat1.sizes()[1];
   172→        n = mat2.sizes()[1];
   173→        k = mat2.sizes()[2] * 2;
   174→        b = mat1.sizes()[0];
   175→    }
   176→    else
   177→    {
   178→        C10_THROW_ERROR(NotImplementedError, "mat1 must be a matrix or a batch of matrices");
   179→    }
   180→
   181→    auto config = maybe_config ? *maybe_config : getDefaultGemmConfig(m, n, k, fp4GemmType);
   182→
   183→    constexpr int alignment = 32;
   184→    TORCH_CHECK(k % alignment == 0, "Expected k to be divisible by ", alignment, ", but got mat1 shape: (",
   185→        mat1.sizes()[0], "x", mat1.sizes()[1], "), k: ", k, ".");
   186→    TORCH_CHECK(n % alignment == 0, "Expected n to be divisible by ", alignment, ", but got mat2 shape: (",
   187→        mat2.sizes()[0], "x", mat2.sizes()[1], ").");
   188→
   189→    if (!out_dtype)
   190→    {
   191→        out_dtype = torch::kHalf;
   192→    }
   193→    TORCH_CHECK(out_dtype == torch::kFloat || out_dtype == torch::kHalf || out_dtype == torch::kBFloat16,
   194→        "out_dtype must be one of fp16/bf16/fp32. It defaults to fp16.");
   195→
   196→    std::vector<int64_t> out_shape = mat1.dim() == 2 ? std::vector<int64_t>{m, n} : std::vector<int64_t>{b, m, n};
   197→    at::Tensor out;
   198→    if (to_userbuffers)
   199→    {
   200→        out = torch_ext::create_userbuffers_tensor(out_shape, out_dtype.value()).first;
   201→    }
   202→    else
   203→    {
   204→        out = at::detail::empty_cuda(out_shape, out_dtype.value(), mat1.device(), std::nullopt);
   205→    }
   206→    switch (out_dtype.value())
   207→    {
   208→    case at::ScalarType::Half:
   209→        runGemm<half>(out, mat1, mat2, mat1Scale, mat2Scale, globalScale, m, n, k, b, config, fp4GemmType);
   210→        break;
   211→    case at::ScalarType::BFloat16:
   212→        runGemm<__nv_bfloat16>(out, mat1, mat2, mat1Scale, mat2Scale, globalScale, m, n, k, b, config, fp4GemmType);
   213→        break;
   214→    case at::ScalarType::Float:
   215→        runGemm<float>(out, mat1, mat2, mat1Scale, mat2Scale, globalScale, m, n, k, b, config, fp4GemmType);
   216→        break;
   217→    default: C10_THROW_ERROR(NotImplementedError, "out_dtype must be one of fp16/bf16/fp32.");
   218→    }
   219→    return out;
   220→}
