   231→    return fp4_bmm_impl(
   232→        mat1, mat2, mat1Scale, mat2Scale, globalScale, static_cast<FP4GemmType>(fp4GemmType), out_dtype);
   233→}
   234→
   235→class FP4GemmRunner : public torch::CustomClassHolder
   236→{
   237→public:
   238→    explicit FP4GemmRunner(at::ScalarType outputDtype, int64_t fp4GemmType)
   239→        : mOutputDtype(outputDtype)
   240→        , mfp4GemmType(static_cast<FP4GemmType>(fp4GemmType))
   241→    {
   242→        if (outputDtype == at::ScalarType::Half)
   243→        {
   244→            if (mfp4GemmType == FP4GemmType::W4A8_MXFP4_MXFP8)
   245→            {
   246→                mGemmRunner = std::make_unique<CutlassFp4GemmRunner<half, FP4GemmType::W4A8_MXFP4_MXFP8>>();
   247→            }
   248→            else if (mfp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
   249→            {
   250→                mGemmRunner = std::make_unique<CutlassFp4GemmRunner<half, FP4GemmType::W4A4_NVFP4_NVFP4>>();
   251→            }
   252→        }
   253→        else if (outputDtype == at::ScalarType::Float)
   254→        {
   255→            if (mfp4GemmType == FP4GemmType::W4A8_MXFP4_MXFP8)
   256→            {
   257→                mGemmRunner = std::make_unique<CutlassFp4GemmRunner<float, FP4GemmType::W4A8_MXFP4_MXFP8>>();
   258→            }
   259→            else if (mfp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
   260→            {
   261→                mGemmRunner = std::make_unique<CutlassFp4GemmRunner<float, FP4GemmType::W4A4_NVFP4_NVFP4>>();
   262→            }
   263→        }
   264→#ifdef ENABLE_BF16
   265→        else if (outputDtype == at::ScalarType::BFloat16)
   266→        {
   267→            if (mfp4GemmType == FP4GemmType::W4A8_MXFP4_MXFP8)
   268→            {
   269→                mGemmRunner = std::make_unique<CutlassFp4GemmRunner<__nv_bfloat16, FP4GemmType::W4A8_MXFP4_MXFP8>>();
   270→            }
   271→            else if (mfp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
   272→            {
   273→                mGemmRunner = std::make_unique<CutlassFp4GemmRunner<__nv_bfloat16, FP4GemmType::W4A4_NVFP4_NVFP4>>();
   274→            }
   275→        }
   276→#endif
   277→        else
   278→        {
   279→            C10_THROW_ERROR(NotImplementedError, "out_dtype must be one of fp16/bf16/fp32.");
   280→        }
   281→        mConfigs = mGemmRunner->getConfigs();
   282→    }
   283→
   284→    at::Tensor runGemm(at::Tensor const& mat1, at::Tensor const& mat2, at::Tensor const& mat1Scale,
   285→        at::Tensor const& mat2Scale, at::Tensor const& globalScale, bool to_userbuffers, int64_t configIdx) const
   286→    {
   287→        tkc::CutlassGemmConfig const* config = nullptr;
   288→        if (configIdx != -1)
   289→        {
   290→            TORCH_CHECK(configIdx >= 0 && configIdx < getNumConfigs());
   291→            config = &mConfigs.at(configIdx);
